import React, { useEffect, useState } from 'react';
import { useParams } from 'react-router-dom';
import ReactMarkdown from 'react-markdown';
import remarkGfm from 'remark-gfm';
import rehypeRaw from 'rehype-raw';
import { Prism as SyntaxHighlighter } from 'react-syntax-highlighter';
import { oneDark } from 'react-syntax-highlighter/dist/esm/styles/prism';
import 'github-markdown-css/github-markdown.css';
import Content from './Content/Content';

function Blog() {
  const { id } = useParams();
  const [blog, setBlog] = useState([]);
  const [isLoading, setIsLoading] = useState(true);

  useEffect(() => {
    setIsLoading(true);
    fetch(`https://raw.githubusercontent.com/MarkIvory2973/MarkIvory2973.github.io/main/blogs/${id}/${id}.md`)
      .then((response) => response.text())
      .then((data) => {
        setBlog([...data.split("#SPLIT#")[0].split("\n"), data.split("#SPLIT#")[1]]);
        setIsLoading(false);
      });
  }, []);

  return (
    <div id='h'>
      <h2>Blogs</h2>
      {!isLoading && (
        <Content img={id} link={`/blog/${id}`} title={blog[0]} date={blog[1]}>
          <article className='markdown-body'>
            <ReactMarkdown
              remarkPlugins={[remarkGfm]}
              rehypePlugins={[rehypeRaw]}
              components={{
                code ({ node, inline, className, children, ...props }) {
                  const match = /language-(\w+)/.exec(className || '')
                  return !inline && match ? (
                    <SyntaxHighlighter
                      children={String(children).replace(/\n$/, '')}
                      style={oneDark}
                      language={match[1]}
                      PreTag="div"
                      showLineNumbers={true}
                      {...props}
                    />
                  ) : (
                    <code className={className} {...props} children={children} />
                  )
                }
              }}
            >{blog[4]}</ReactMarkdown>
          </article>
        </Content>
      )}
      {isLoading && (
        <button id='loading'>Loading...</button>
      )}
    </div>
  )
}

export default Blog;
