import { Link } from 'react-router-dom';
import './Content.css'

function Content(props) {
  return (
    <div id='v'>
      <img id='header' src={`https://raw.githubusercontent.com/MarkIvory2973/MarkIvory2973.github.io/main/blogs/${props.img}/${props.img}.webp`} />
      <Link id='title' to={props.link}>{props.title}</Link>
      <p id='date'>{props.date}</p>
      {props.children}
    </div>
  );
}

export default Content;
