import React, { useEffect, useState } from 'react';
import Content from "./Content/Content";

function Home() {
  const [latestBlogs, setLatestblogs] = useState([]);
  const [isLoading, setIsLoading] = useState(true);

  useEffect(() => {
    setIsLoading(true);
    fetch("https://raw.githubusercontent.com/MarkIvory2973/MarkIvory2973.github.io/main/blogs/blogCount")
      .then((response) => response.json())
      .then((blogCount) => {
        const tempLatestblogs = [];

        const requests = Array.from({length: 5}, (_, i) => {
          const id = blogCount-i;
          if (id > 0) {
            return fetch(`https://raw.githubusercontent.com/MarkIvory2973/MarkIvory2973.github.io/main/blogs/${id}/${id}.md`)
              .then((response) => response.text())
          }
          });
        Promise.all(requests)
          .then((responses) => {
            responses.forEach((data, i) => {
              const id = blogCount-i;
              if (id > 0) {
                tempLatestblogs.push([id, ...data.split("#SPLIT#")[0].split("\n")]);
              }
            });

            setLatestblogs(tempLatestblogs);
            setIsLoading(false);
          });
      });
  }, []);

  return (
    <div id='h'>
      <h2>Latest Blogs</h2>
      {latestBlogs.map((blog, _) => (
        <Content key={blog[0]} img={blog[0]} link={`/blog/${blog[0]}`} title={blog[1]} date={blog[2]}>
          <p id='preview'>{blog[3]}</p>
        </Content>
      ))}
      {isLoading && (
        <button id='loading'>Loading...</button>
      )}
    </div>
  );
}

export default Home;
