import React, { useEffect, useState } from 'react';
import Content from "./Content/Content";

function Blogs() {
  const [blogs, setBlogs] = useState([]);
  const [currentPage, setCurrentPage] = useState(1);
  const [isLoading, setIsLoading] = useState(true);
  const [isLoaded, setIsLoaded] = useState(false);

  useEffect(() => {
    setIsLoading(true);
    fetch("https://raw.githubusercontent.com/MarkIvory2973/MarkIvory2973.github.io/main/blogs/blogCount")
      .then((response) => response.json())
      .then((blogCount) => {
        const tempBlogs = [];

        const requests = Array.from({length: 10}, (_, i) => {
          const id = blogCount-i-10*(currentPage-1);
          if (id > 0) {
            return fetch(`https://raw.githubusercontent.com/MarkIvory2973/MarkIvory2973.github.io/main/blogs/${id}/${id}.md`)
              .then((response) => response.text());
          }
        });
        Promise.all(requests)
          .then((responses) => {
            responses.forEach((data, i) => {
              const id = blogCount-i-10*(currentPage-1);
              if (id > 0) {
                tempBlogs.push([id, ...data.split("#SPLIT#")[0].split("\n")]);
              } else {
                setIsLoaded(true);
              }
            });
            
            setBlogs([...blogs, ...tempBlogs]);
            setIsLoading(false);
          })
      });
  }, [currentPage]);

  function ShowMore() {
    setCurrentPage(currentPage + 1);
  }

  return (
    <div id='h'>
      <h2>Blogs</h2>
      {blogs.map((blog) => (
        <Content key={blog[0]} img={blog[0]} link={`/blog/${blog[0]}`} title={blog[1]} date={blog[2]}>
          <p id='preview'>{blog[3]}</p>
        </Content>
      ))}
      {!isLoaded && !isLoading && (
        <button id='showmore' onClick={ShowMore}>Show More</button>
      )}
      {!isLoaded && isLoading && (
        <button id='loading'>Loading...</button>
      )}
    </div>
  );
}

export default Blogs;
